class Animal {
    void makeSound() {
        System.out.println("Animal sound");
    }
}

class Dog extends Animal {
    @Override
    void makeSound() {
        System.out.println("Woof!");
    }

    void wagTail() {
        System.out.println("Tail wagging!");
    }
}

class Cat extends Animal {
    @Override
    void makeSound() {
        System.out.println("Meow!");
    }

    void purr() {
        System.out.println("Purr...");
    }
}

public class PolymorphismExample {
    public static void main(String[] args) {
        // Compile-time polymorphism (method overloading)
        System.out.println("=== Compile-time Polymorphism ===");
        Calculator calc = new Calculator();
        System.out.println("Add 2 numbers: " + calc.add(5, 3));
        System.out.println("Add 3 numbers: " + calc.add(5, 3, 2));
        System.out.println("Add 2 doubles: " + calc.add(5.5, 3.3));

        // Runtime polymorphism (method overriding)
        System.out.println("=== Runtime Polymorphism ===");
        Animal myAnimal;

        myAnimal = new Dog();
        myAnimal.makeSound();  // Calls Dog's version
        // myAnimal.wagTail(); // ERROR! Animal reference doesn't know about Dog methods

        myAnimal = new Cat();
        myAnimal.makeSound();  // Calls Cat's version

        // Upcasting
        System.out.println("=== Upcasting ===");
        Dog dog = new Dog();
        Animal animal = dog;  // Upcast (Dog -> Animal) — automatic
        animal.makeSound();   // Still calls Dog's version

        // Downcasting (with instanceof check)
        System.out.println("=== Downcasting ===");
        Animal someAnimal = new Dog();
        if (someAnimal instanceof Dog) {
            Dog dog2 = (Dog) someAnimal;  // Downcast (Animal -> Dog)
            dog2.wagTail();  // Now we can call Dog-specific methods
        }

        if (someAnimal instanceof Cat) {
            System.out.println("This is a Cat");
        } else {
            System.out.println("This is NOT a Cat");
        }
    }
}

class Calculator {
    // Overloaded methods (compile-time polymorphism)
    int add(int a, int b) {
        return a + b;
    }

    int add(int a, int b, int c) {
        return a + b + c;
    }

    double add(double a, double b) {
        return a + b;
    }
}

